import { defineComponentSlotStyle } from "@yamada-ui/react"
import { sliderStyle } from "../slider"

export const hueSliderStyle = defineComponentSlotStyle({
  base: {
    overlay: {
      position: "absolute",
      rounded: "{track-rounded}",
      top: "0",
      _horizontal: {
        h: "full",
        left: "calc({thumb-size} / 2 * -1)",
        w: "calc(full + {thumb-size})",
      },
      _vertical: {
        h: "calc(full + {thumb-size})",
        top: "calc({thumb-size} / 2 * -1)",
        w: "full",
      },
    },
    root: {},
    thumb: {
      "--thumb-stroke": "colors.white",
      borderWidth: "3px",
      boxShadow: "md",
    },
    track: {
      flex: "inherit",
      _horizontal: {
        ms: "calc({thumb-size} / 2)",
        w: "calc(full - {thumb-size})",
      },
      _vertical: {
        h: "calc(full - {thumb-size})",
        mt: "calc({thumb-size} / 2)",
      },
    },
  },

  props: {
    /**
     * The shape of the thumb.
     *
     * @default 'circle'
     */
    shape: {
      circle: {
        root: {
          ...sliderStyle.props?.shape.circle.root,
          "--track-rounded": "{thumb-rounded}",
        },
      },
      rounded: {
        root: {
          ...sliderStyle.props?.shape.rounded.root,
          "--track-rounded": "{thumb-rounded}",
        },
      },
      square: {
        root: {
          ...sliderStyle.props?.shape.square.root,
          "--track-rounded": "{thumb-rounded}",
        },
      },
    },
  },

  sizes: {
    xs: {
      root: {
        "--thumb-size": sliderStyle.sizes?.sm.root["--thumb-size"],
        "--track-size": sliderStyle.sizes?.sm.root["--thumb-size"],
      },
    },
    sm: {
      root: {
        "--thumb-size": sliderStyle.sizes?.sm.root["--thumb-size"],
        "--track-size": sliderStyle.sizes?.sm.root["--thumb-size"],
      },
    },
    md: {
      root: {
        "--thumb-size": sliderStyle.sizes?.md.root["--thumb-size"],
        "--track-size": sliderStyle.sizes?.md.root["--thumb-size"],
      },
    },
    lg: {
      root: {
        "--thumb-size": sliderStyle.sizes?.lg.root["--thumb-size"],
        "--track-size": sliderStyle.sizes?.lg.root["--thumb-size"],
      },
    },
    xl: {
      root: {
        "--thumb-size": sliderStyle.sizes?.lg.root["--thumb-size"],
        "--track-size": sliderStyle.sizes?.lg.root["--thumb-size"],
      },
    },
  },

  defaultProps: {
    size: "md",
    shape: "circle",
  },
})

export type HueSliderStyle = typeof hueSliderStyle

import { vi } from "vitest"
import { a11y, page, render } from "#test/browser"
import { HueSlider } from "."

describe("<HueSlider />", () => {
  test("renders component correctly", async () => {
    await a11y(<HueSlider.Root defaultValue={180} />)
  })

  test("sets `displayName` correctly", () => {
    expect(HueSlider.Root.displayName).toBe("HueSliderRoot")
    expect(HueSlider.Track.displayName).toBe("HueSliderTrack")
    expect(HueSlider.Thumb.displayName).toBe("HueSliderThumb")
    expect(HueSlider.Overlay.displayName).toBe("HueSliderOverlay")
  })

  test("sets `className` correctly", async () => {
    await render(
      <HueSlider.Root
        data-testid="slider"
        defaultValue={180}
        overlayProps={{ "data-testid": "overlay" }}
        trackProps={{ "data-testid": "track" }}
      />,
    )
    const root = page.getByTestId("slider")
    const track = page.getByTestId("track")
    const thumb = page.getByRole("slider")
    const overlay = page.getByTestId("overlay").first()
    await expect.element(root).toHaveClass("ui-hue-slider__root")
    await expect.element(track).toHaveClass("ui-hue-slider__track")
    await expect.element(thumb).toHaveClass("ui-hue-slider__thumb")
    await expect.element(overlay).toHaveClass("ui-hue-slider__overlay")
  })

  test("merges `overlayProps` and `layers` props on overlay", async () => {
    const onOverlayClick = vi.fn()
    const onLayerClick = vi.fn()
    await render(
      <HueSlider.Root
        defaultValue={0}
        overlayProps={{
          className: "from-overlay",
          style: { color: "red", pointerEvents: "auto" },
          "data-testid": "overlay",
          layers: [
            {
              className: "from-layer",
              style: { backgroundColor: "blue", pointerEvents: "auto" },
              onClick: onLayerClick,
            },
          ],
          onClick: onOverlayClick,
        }}
      />,
    )

    const overlay = page.getByTestId("overlay")

    await expect
      .element(overlay)
      .toHaveClass("ui-hue-slider__overlay", "from-overlay", "from-layer")
    await expect.element(overlay).toHaveStyle({ color: "rgb(255, 0, 0)" })
    await expect
      .element(overlay)
      .toHaveStyle({ backgroundColor: "rgb(0, 0, 255)" })

    overlay
      .element()
      .dispatchEvent(
        new MouseEvent("click", { bubbles: true, cancelable: true }),
      )

    expect(onOverlayClick).toHaveBeenCalledTimes(1)
    expect(onLayerClick).toHaveBeenCalledTimes(1)
  })

  test("renders custom children correctly", async () => {
    await render(
      <HueSlider.Root defaultValue={180}>
        <div data-testid="custom-child">custom</div>
      </HueSlider.Root>,
    )

    await expect.element(page.getByTestId("custom-child")).toBeVisible()
  })

  test("sets aria attributes correctly", async () => {
    await render(<HueSlider.Root defaultValue={180} />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuenow", "180")
    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuetext", "180°, Cyan")
    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuemin", "0")
    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuemax", "360")
    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-orientation", "horizontal")
  })

  test("sets vertical orientation correctly", async () => {
    await render(
      <HueSlider.Root
        defaultValue={180}
        orientation="vertical"
        overlayProps={{ "data-testid": "overlay" }}
      />,
    )

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-orientation", "vertical")
    await expect
      .element(page.getByTestId("overlay").first())
      .toHaveAttribute("data-orientation", "vertical")
  })

  test.each([
    [29, "Red"],
    [30, "Yellow"],
    [89, "Yellow"],
    [90, "Green"],
    [149, "Green"],
    [150, "Cyan"],
    [209, "Cyan"],
    [210, "Blue"],
    [269, "Blue"],
    [270, "Magenta"],
    [329, "Magenta"],
    [330, "Red"],
  ])("sets aria-valuetext for each hue correctly", async (hue, color) => {
    await render(<HueSlider.Root defaultValue={hue} />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuetext", `${hue}°, ${color}`)
  })

  test("controlled slider value updates correctly", async () => {
    const { rerender } = await render(<HueSlider.Root value={60} />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuenow", "60")
    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuetext", "60°, Yellow")

    await rerender(<HueSlider.Root value={180} />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuenow", "180")
    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-valuetext", "180°, Cyan")
  })

  test("disabled HueSlider renders correctly", async () => {
    await render(<HueSlider.Root disabled />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-disabled")
  })

  test("readonly HueSlider renders correctly", async () => {
    await render(<HueSlider.Root readOnly />)

    await expect
      .element(page.getByRole("slider"))
      .toHaveAttribute("aria-readonly")
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps, WithoutThemeProps } from "@yamada-ui/react"
import type { HueSliderStyle } from "./hue-slider.style"
import { useCallback, useMemo } from "react"
import { createSlotComponent, mergeProps, styled } from "@yamada-ui/react"
import { useValue } from "../../hooks/use-value"
import { useI18n } from "../../providers/i18n-provider"
import { Slider } from "../slider"
import { hueSliderStyle } from "./hue-slider.style"

interface ComponentContext extends Pick<
  Required<HueSliderRootProps>,
  "max" | "min" | "orientation"
> {}

export interface HueSliderRootProps
  extends
    WithoutThemeProps<
      Omit<
        Slider.RootProps,
        | "betweenThumbs"
        | "marks"
        | "marksProps"
        | "max"
        | "rangeFill"
        | "rangeProps"
        | "thumbFill"
        | "thumbProps"
        | "trackFill"
        | "trackProps"
      >,
      HueSliderStyle
    >,
    ThemeProps<HueSliderStyle> {
  /**
   * The maximum allowed value of the slider. Cannot be less than min.
   *
   * @default 360
   */
  max?: number
  /**
   * Props for the overlay element.
   */
  overlayProps?: HueSliderOverlayProps
  /**
   * Props for the thumb element.
   */
  thumbProps?: HueSliderThumbProps
  /**
   * Props for the track element.
   */
  trackProps?: HueSliderTrackProps
}

const {
  ComponentContext,
  PropsContext: HueSliderPropsContext,
  useComponentContext,
  usePropsContext: useHueSliderPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<HueSliderRootProps, HueSliderStyle, ComponentContext>(
  "hue-slider",
  hueSliderStyle,
)

export { HueSliderPropsContext, useHueSliderPropsContext }

/**
 * `HueSlider` is a component used to allow the user to select a color hue.
 *
 * @see https://yamada-ui.com/docs/components/hue-slider
 */
export const HueSliderRoot = withProvider<"input", HueSliderRootProps>(
  ({
    children,
    max = 360,
    min = 0,
    orientation: orientationProp = "horizontal",
    overlayProps,
    thumbProps,
    trackProps,
    ...rest
  }) => {
    const { t } = useI18n("hueSlider")
    const orientation = useValue(orientationProp)
    const computedChildren = useMemo(() => {
      if (children) return children

      return (
        <HueSliderTrack {...trackProps}>
          <HueSliderThumb {...thumbProps} />

          <HueSliderOverlay {...overlayProps} />
        </HueSliderTrack>
      )
    }, [children, overlayProps, thumbProps, trackProps])
    const context = useMemo(
      () => ({ max, min, orientation }),
      [max, min, orientation],
    )
    const getColorName = useCallback(
      (hue: number): string => {
        if (hue < 30 || hue >= 330) return t("Red")
        if (hue < 90) return t("Yellow")
        if (hue < 150) return t("Green")
        if (hue < 210) return t("Cyan")
        if (hue < 270) return t("Blue")
        return t("Magenta")
      },
      [t],
    )
    const getAriaValueText = useCallback(
      (hue: number) => `${hue}°, ${getColorName(hue)}`,
      [getColorName],
    )

    return (
      <ComponentContext value={context}>
        <Slider.Root
          getAriaValueText={getAriaValueText}
          max={max}
          min={min}
          orientation={orientation}
          {...rest}
        >
          {computedChildren}
        </Slider.Root>
      </ComponentContext>
    )
  },
  "root",
)({
  "--thumb-fill": "transparent",
  "--track-fill": "transparent",
})

export interface HueSliderTrackProps extends Slider.TrackProps {}

export const HueSliderTrack = withContext<"div", HueSliderTrackProps>(
  Slider.Track,
  "track",
)()

export interface HueSliderOverlayProps extends HTMLStyledProps {
  /**
   * The layers used for the overlay element.
   */
  layers?: HTMLStyledProps[]
}

export const HueSliderOverlay = withContext<"fragment", HueSliderOverlayProps>(
  ({ layers, ...rest }) => {
    const { max, min, orientation } = useComponentContext()

    layers ??= [
      {
        bgGradient: `linear(${[
          orientation === "horizontal" ? "to-r" : "to-t",
          ...Array.from({ length: 7 }).map(
            (_, index) =>
              `hsl(${Math.round(min + ((max - min) / 6) * index)}, 100%, 50%)`,
          ),
        ].join(", ")})`,
        boxShadow: "inner",
      },
    ]

    return (
      <>
        {layers.map((props, index) => (
          <styled.div
            key={index}
            data-orientation={orientation}
            {...mergeProps(rest, props)()}
          />
        ))}
      </>
    )
  },
  "overlay",
)()

export interface HueSliderThumbProps extends Slider.ThumbProps {}

export const HueSliderThumb = withContext<"div", HueSliderThumbProps>(
  Slider.Thumb,
  "thumb",
)()
